public class TextSerializer extends XMLSerializer { private static final String UTF_8 = "UTF-8" ; private static final String TXT = "text" ; public TextSerializer ( ) { super ( ) ; super . setOmitXmlDeclaration ( true ) ; } @ Override public void setDocumentLocator ( final Locator locator ) { } @ Override public void processingInstruction ( final String target , final String data ) throws SAXException { } @ Override public void startDTD ( final String name , final String publicId , final String systemId ) throws SAXException { } @ Override public void endDTD ( ) throws SAXException { } @ Override public void startElement ( final String uri , final String loc , final String raw , final Attributes atts ) throws SAXException { } @ Override public void endElement ( final String uri , final String name , final String raw ) throws SAXException { } public static TextSerializer createPlainSerializer ( ) { final TextSerializer serializer = new TextSerializer ( ) ; serializer . setContentType ( "text/plain; charset=" + UTF_8 ) ; serializer . setEncoding ( UTF_8 ) ; serializer . setMethod ( TXT ) ; return serializer ; } }